const input = $input.all();
const parentItems = $('Filtrar Próximos 2h').all();
const results = [];
for (let i = 0; i < input.length; i++) {
  const item = input[i];
  if (!item.json.propertyName) {
    const parentJson = parentItems[i] ? parentItems[i].json : {};
    results.push({
      json: {
        ...parentJson,
        propertyName: item.json.propertyName
      }
    });
  }
}
return results;

const bookings = $input.all();
const results = [];
const now = new Date();

for (const item of bookings) {
  const b = item.json;
  if (b && b.inicio) {
    // Ignora qualquer offset retornado pelo banco (ex: +00:00) extraindo apenas a data/hora e forçando o fuso do Brasil (-03:00)
    const localPart = b.inicio.slice(0, 19);
    const dateStr = localPart + '-03:00';
    const bookingTime = new Date(dateStr);
    const diffMs = bookingTime - now;
    const diffMinutes = diffMs / (1000 * 60);

    // DESABILITADO TEMPORARIAMENTE PARA TESTES MANUAIS (Aceita qualquer horário)
    if (true) {
      const clientName = b.clientes?.nome || 'Cliente';
      const phoneRaw = b.clientes?.telefone || '';

      let cleanPhone = phoneRaw.replace(/\D/g, '');
      if (cleanPhone.length > 0) {
        if (!cleanPhone.startsWith('55')) {
          cleanPhone = '55' + cleanPhone;
        }
        // Ajuste de 9 dígitos para WAHA (DDD > 28)
        if (cleanPhone.length === 13) {
          const ddd = parseInt(cleanPhone.slice(2, 4));
          if (ddd > 28) {
            cleanPhone = cleanPhone.slice(0, 4) + cleanPhone.slice(5);
          }
        }
        const chatId = `${cleanPhone}@c.us`;
        results.push({
          json: {
            bookingId: b.id,
            clientName,
            inicio: b.inicio,
            chatId,
            horario: localPart.split('T')[1].slice(0, 5)
          }
        });
      }
    }
  }
}
return results;

